    override fun onNewIntent(intent: Intent) {
        super.onNewIntent(intent)
        setIntent(intent)
        lifecycleScope.launch {
            val shared = withContext(Dispatchers.Default) { extractSharedContent(intent) }
            processSharedContent(shared)
            finish()
        }
    }

    private fun extractSharedContent(intent: Intent?): SharedContent {
        if (intent == null) return SharedContent.Empty

        val action = intent.action
        val type = intent.type

        if (action != Intent.ACTION_SEND && action != Intent.ACTION_SEND_MULTIPLE) {
            return SharedContent.Empty
        }

        val uris = LinkedHashSet<Uri>()
        val texts = LinkedHashSet<String>()

        fun addClipData(clipData: ClipData?) {
            if (clipData == null) return
            for (i in 0 until clipData.itemCount) {
                val item = clipData.getItemAt(i)
                item.uri?.let { uris.add(it) }
                item.text?.toString()?.takeIf { it.isNotBlank() }?.let { texts.add(it) }
                item.coerceToText(this)?.toString()?.takeIf { it.isNotBlank() }?.let { texts.add(it) }
            }
        }

        addClipData(intent.clipData)

        when (action) {
            Intent.ACTION_SEND -> {
                intent.getParcelableExtra<Uri>(Intent.EXTRA_STREAM)?.let { uris.add(it) }
                intent.getStringExtra(Intent.EXTRA_TEXT)?.takeIf { it.isNotBlank() }?.let { texts.add(it) }
            }
            Intent.ACTION_SEND_MULTIPLE -> {
                intent.getParcelableArrayListExtra<Uri>(Intent.EXTRA_STREAM)?.forEach { uris.add(it) }
                intent.getStringArrayListExtra(Intent.EXTRA_TEXT)?.forEach { if (it.isNotBlank()) texts.add(it) }
            }
        }

        val normalizedTexts = texts.map { it.trim() }.filter { it.isNotEmpty() }
        val normalizedUris = uris.toList()

        val urlCandidates = LinkedHashSet<String>()
        normalizedTexts.forEach { t ->
            extractUrls(t).forEach { urlCandidates.add(it) }
        }

        val imageUris = normalizedUris.filter { uri ->
            val mime = contentResolver.getType(uri)
            (mime?.startsWith("image/") == true) || (type?.startsWith("image/") == true)
        }

        val otherUris = normalizedUris - imageUris.toSet()

        return SharedContent(
            urls = urlCandidates.toList(),
            imageUris = imageUris,
            otherUris = otherUris,
            rawTexts = normalizedTexts
        )
    }

    private fun extractUrls(text: String): List<String> {
        val regex = Regex("""(?i)\b((?:https?://|www\.)[^\s<>()]+)""")
        return regex.findAll(text).map { match ->
            val v = match.value
            if (v.startsWith("www.", ignoreCase = true)) "https://$v" else v
        }.toList()
    }

